WITH deleted AS (
  DELETE FROM cron.job_run_details
  WHERE ctid >= ${safeCtidStart}::tid
    AND ctid < ${safeCtidEnd}::tid
    AND end_time < now() - interval ${literal(interval)}
  RETURNING 1
)
SELECT count(*) as deleted_count FROM deleted;

